// Point-in-polygon (ray casting) — funciona con [lat,lng] o [lng,lat] siempre que sea consistente
window.pointInPolygon = function(point, vs) {
  const x = point[0], y = point[1];
  let inside = false;
  for (let i = 0, j = vs.length - 1; i < vs.length; j = i++) {
    const xi = vs[i][0], yi = vs[i][1];
    const xj = vs[j][0], yj = vs[j][1];
    const intersect = ((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
};

// Dado lat/lng → nombre de plataforma o null
window.findPlataforma = function(lat, lng) {
  if (lat == null || lng == null) return null;
  for (const p of window.PLATAFORMAS_GEO) {
    for (const ring of p.rings) {
      if (window.pointInPolygon([lat, lng], ring)) return p.name;
    }
  }
  return null;
};
